import ArgsParser from 'zsh.js/args-parser';

export default function (args, stdin, stdout, stderr, next) {
  try {
    stdout.write(ArgsParser.parseStrings(args.raw).join(' '));
  } catch (err) {
    stderr.write('zsh: ' + err.message);
  }

  next();
}

